 49‚Üí            is LoadingItem, null -> {
 50‚Üí                when (itemLayoutType) {
 51‚Üí                    STANDARD -> VIEW_TYPE_LOADING
 52‚Üí                    COMPACT -> VIEW_TYPE_LOADING_COMPACT
