 73‚Üí            VIEW_TYPE_POST -> {
 74‚Üí                PostListItemViewHolder.Standard(parent, imageManager, uiHelpers)
 75‚Üí            }
 76‚Üí            VIEW_TYPE_POST_COMPACT -> {
 77‚Üí                PostListItemViewHolder.Compact(parent, imageManager, uiHelpers)
