 86‚Üí    override fun onBindViewHolder(holder: ViewHolder, position: Int) {
 87‚Üí        // The only holders that require special setup are PostListItemViewHolder and LoadingViewHolder subclasses
 88‚Üí        if (holder is PostListItemViewHolder) {
