135‚Üíprivate val PostListDiffItemCallback = object : DiffUtil.ItemCallback<PostListItemType>() {
136‚Üí    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
137‚Üí        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
138‚Üí            return true
139‚Üí        }
140‚Üí        if (oldItem is LoadingItem && newItem is LoadingItem) {
141‚Üí            return oldItem.localOrRemoteId == newItem.localOrRemoteId
142‚Üí        }
143‚Üí        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
144‚Üí            return oldItem.data.localPostId == newItem.data.localPostId
145‚Üí        }
146‚Üí        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
147‚Üí            return when (oldItem.localOrRemoteId) {
148‚Üí                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
149‚Üí                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
150‚Üí            }
151‚Üí        }
152‚Üí        return false
153‚Üí    }
154‚Üí
155‚Üí    override fun areContentsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
156‚Üí        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
157‚Üí            return true
158‚Üí        }
159‚Üí        if (oldItem is LoadingItem && newItem is LoadingItem) {
160‚Üí            return when (oldItem.localOrRemoteId) {
161‚Üí                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
162‚Üí                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
163‚Üí            }
164‚Üí        }
165‚Üí        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
166‚Üí            return oldItem.data == newItem.data
167‚Üí        }
168‚Üí        return false
169‚Üí    }
170‚Üí
171‚Üí    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
172‚Üí        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
173‚Üí            /**
174‚Üí             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
175‚Üí             *
176‚Üí             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
177‚Üí             * suppresses the default ItemAnimator, which is all we need in this case.
178‚Üí             */
179‚Üí            if (oldItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
180‚Üí                newItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
181‚Üí                oldItem.data.progressBarUiState.progress != newItem.data.progressBarUiState.progress
182‚Üí            ) {
183‚Üí                return true
184‚Üí            }
185‚Üí        }
186‚Üí        return super.getChangePayload(oldItem, newItem)
187‚Üí    }
188‚Üí}
